arrayPipelines.data:
[
	{
		$match: {
			"workflow_name": "SOW_WORKFLOW"
		}
	},
	{
		$match: {{ workflow_logs_filter_js.getMatchQuery() }}
	},
		{ $sort: { started_at: -1 } },
	{
	$project: {
	_id: 0,
	created_at: 1,
	event_subject: 1,
	client_id: 1,
	workflow_name: 1,
	attendee_emails: 1,
	customer_name: "$processed_emails.email_content.customer_name",
	call_name: "$processed_emails.email_content.call_name",
	call_date: "$processed_emails.email_content.call_date",

	executive_snapshot: "$processed_emails.email_content.executive_snapshot_context.engagement_summary",
	engagement_duration: "$processed_emails.email_content.executive_snapshot_context.timeline.duration",
	engagement_start_date: "$processed_emails.email_content.executive_snapshot_context.timeline.start_date",
	prospect_vendor: "$processed_emails.email_content.executive_snapshot_context.parties.prospect",

	commercials_text: {
	$let: {
	vars: { cms: { $ifNull: ["$processed_emails.email_content.executive_snapshot_context.commercials", []] } },
in: {
	$reduce: {
		input: "$$cms",
		initialValue: "",
		in: {
			$concat: [
				{ $cond: [{ $eq: ["$$value", ""] }, "", " | "] },
				"$$this"
			]
		}
	}
}
}
},

